import{_ as t,o as i,c as a,a2 as o}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Chapter 4: Building a Tool System","description":"Design and implement a trait-based tool system with JSON schema definitions, a registry, and dispatch logic.","frontmatter":{"title":"Chapter 4: Building a Tool System","description":"Design and implement a trait-based tool system with JSON schema definitions, a registry, and dispatch logic."},"headers":[],"relativePath":"learn/project/04-building-a-tool-system/index.md","filePath":"learn/project/04-building-a-tool-system/index.md"}'),l={name:"learn/project/04-building-a-tool-system/index.md"};function s(r,e,n,h,d,c){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="building-a-tool-system" tabindex="-1">Building a Tool System <a class="header-anchor" href="#building-a-tool-system" aria-label="Permalink to &quot;Building a Tool System&quot;">​</a></h1><p>This chapter gives your agent hands. The agentic loop from Chapter 3 can detect when the model wants to use a tool, but until now there was nothing to execute. Here you build the complete tool infrastructure: a Rust trait that every tool must implement, a JSON schema system that tells the model what tools are available and what arguments they accept, and a registry that dispatches tool calls to the right implementation at runtime.</p><p>The design is deliberately extensible. You define a <code>Tool</code> trait with methods for name, description, schema, and execution. Any struct that implements this trait can be registered in the tool registry and becomes immediately available to the model. This pattern means adding a new tool later -- a shell executor, a web search, a database query -- requires writing one struct and registering it, with no changes to the loop or dispatch logic.</p><p>You will also implement input validation against JSON schemas, proper error handling that distinguishes between tool failures and system errors, and the complete lifecycle of a tool call from the model&#39;s request through execution to the observation that feeds back into the conversation.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Design a Tool trait that defines the contract every tool must satisfy</li><li>Generate JSON schema definitions that describe tool inputs to the model</li><li>Build a tool registry that maps tool names to implementations</li><li>Implement dispatch logic that routes tool calls and handles errors</li><li>Validate tool inputs against their schemas before execution</li><li>Understand the full tool lifecycle from request to observation</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/04-building-a-tool-system/01-what-are-tools.html">What Are Tools</a></li><li><a href="/project/04-building-a-tool-system/02-tool-trait-design.html">Tool Trait Design</a></li><li><a href="/project/04-building-a-tool-system/03-json-schema-basics.html">JSON Schema Basics</a></li><li><a href="/project/04-building-a-tool-system/04-defining-tool-schemas.html">Defining Tool Schemas</a></li><li><a href="/project/04-building-a-tool-system/05-tool-registry.html">Tool Registry</a></li><li><a href="/project/04-building-a-tool-system/06-tool-dispatch.html">Tool Dispatch</a></li><li><a href="/project/04-building-a-tool-system/07-input-validation.html">Input Validation</a></li><li><a href="/project/04-building-a-tool-system/08-executing-tools.html">Executing Tools</a></li><li><a href="/project/04-building-a-tool-system/09-error-handling.html">Error Handling</a></li><li><a href="/project/04-building-a-tool-system/10-tool-results-as-observations.html">Tool Results as Observations</a></li><li><a href="/project/04-building-a-tool-system/11-adding-tool-descriptions.html">Adding Tool Descriptions</a></li><li><a href="/project/04-building-a-tool-system/12-testing-tools.html">Testing Tools</a></li><li><a href="/project/04-building-a-tool-system/13-the-tool-lifecycle.html">The Tool Lifecycle</a></li><li><a href="/project/04-building-a-tool-system/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 3 completed (working agentic loop with tool-call detection and observation feeding)</li><li>Understanding of Rust traits, dynamic dispatch, and serde serialization</li></ul>',10)])])}const p=t(l,[["render",s]]);export{u as __pageData,p as default};
